function getOrdinal(n) {
  if (n % 100 >= 11 && n % 100 <= 13) return n + "th";
  switch (n % 10) {
    case 1: return n + "st";
    case 2: return n + "nd";
    case 3: return n + "rd";
    default: return n + "th";
  }
}

function parseDateFromText(text) {
  const cleaned = text
    .toLowerCase()
    .replace(/(\d+)(st|nd|rd|th)/g, "$1")
    .replace(/,/g, "");

  const patterns = [
    /\b(\d{1,2}) (\w+) (\d{4})\b/,        // 10 june 2026
    /\b(\w+) (\d{1,2}) (\d{4})\b/,        // june 10 2026
    /\b(\d{4})-(\d{2})-(\d{2})\b/,        // 2026-06-10
    /\b(\d{1,2})\/(\d{1,2})\/(\d{4})\b/   // 10/06/2026
  ];

  for (const pattern of patterns) {
    const match = cleaned.match(pattern);
    if (!match) continue;

    let date;

    if (pattern.source.includes("-")) {
      date = new Date(`${match[1]}-${match[2]}-${match[3]}`);
    } else if (pattern.source.includes("/")) {
      const day = match[1];
      const month = match[2];
      const year = match[3];
      date = new Date(`${year}-${month}-${day}`);
    } else {
      date = new Date(match.slice(1).join(" "));
    }

    if (!isNaN(date)) {
      return date;
    }
  }

  return null;
}

const date = parseDateFromText(query);

if (!date) {
