const weekdays = [
  "Sunday",
  "Monday",
  "Tuesday",
  "Wednesday",
  "Thursday",
  "Friday",
  "Saturday"
];

const months = [
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December"
];

const weekday = weekdays[date.getDay()];
const day = getOrdinal(date.getDate());
const month = months[date.getMonth()];
const year = date.getFullYear();

return `${weekday} ${day} of ${month} ${year}`;
